INSERT INTO `mdl_h5p_libraries` VALUES (1,'FontAwesome','Font Awesome',4,5,4,0,0,'','','h5p-font-awesome.min.css','','',NULL,NULL,NULL,NULL,NULL,NULL,1),(2,'H5P.Accordion','Accordion',1,0,33,1,0,'iframe','h5p-accordion.js','h5p-accordion.css','','[\n  {\n    \"name\": \"panels\",\n    \"type\": \"list\",\n    \"label\": \"Panels\",\n    \"entity\": \"panel\",\n    \"max\": 100,\n    \"min\": 1,\n    \"field\": {\n      \"name\": \"content\",\n      \"type\": \"group\",\n      \"label\": \"Content\",\n      \"importance\": \"high\",\n      \"entity\": \"content\",\n      \"fields\": [\n        {\n          \"name\": \"title\",\n          \"type\": \"text\",\n          \"label\": \"Title\",\n          \"importance\": \"high\"\n        },\n        {\n          \"name\": \"content\",\n          \"type\": \"library\",\n          \"label\": \"Content type\",\n          \"importance\": \"medium\",\n          \"entity\": \"content\",\n          \"options\": [\n            \"H5P.AdvancedText 1.1\"\n          ]\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"hTag\",\n    \"type\": \"select\",\n    \"label\": \"H tags for labels (does not affect the size of the label)\",\n    \"importance\": \"low\",\n    \"description\": \"The h tag used on the labels. Normally H2 but if this belongs under an H2 heading use H3. Does not affect the size of the labels, only used for semantical purposes.\",\n    \"options\": [\n      {\n        \"value\": \"h2\",\n        \"label\": \"H2\"\n      },\n      {\n        \"value\": \"h3\",\n        \"label\": \"H3\"\n      },\n      {\n        \"value\": \"h4\",\n        \"label\": \"H4\"\n      }\n    ],\n    \"default\": \"h2\"\n  }\n]\n',NULL,1,5,NULL,'https://h5p.org/tutorial-accordion','https://h5p.org/accordion',1),(3,'H5P.AdvancedText','Text',1,1,14,0,0,'','text.js','text.css','','[\n  {\n    \"name\": \"text\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"label\": \"Text\",\n    \"importance\": \"high\",\n    \"enterMode\": \"p\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"del\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ],\n    \"font\": {\n      \"size\": true,\n      \"color\": true,\n      \"background\": true\n    }\n  }\n]\n',NULL,NULL,NULL,'{\"disable\":0,\"disableExtraTitleField\":1}',NULL,NULL,1),(4,'H5P.ArithmeticQuiz','Arithmetic Quiz',1,1,20,1,0,'iframe','js/algebra.min.js, js/arithmetic-quiz.js, js/sound-effects.js, js/countdown-widget.js, js/timer-widget.js, js/intro-page.js, js/qe-generator.js, js/qa-generator.js, js/game-page.js, js/result-page.js','css/arithmetic-quiz.css','','[\n  {\n    \"name\": \"intro\",\n    \"type\": \"text\",\n    \"label\": \"Intro\",\n    \"importance\": \"high\",\n    \"description\": \"The intro text (maximum 100 characters)\",\n    \"maxLength\": 100,\n    \"optional\": true\n  },\n  {\n    \"name\": \"quizType\",\n    \"type\": \"select\",\n    \"label\": \"Quiz type\",\n    \"importance\": \"high\",\n    \"options\": [\n      {\n        \"value\": \"arithmetic\",\n        \"label\": \"Arithmetic Operations Quiz\"\n      },\n      {\n        \"value\": \"linearEquation\",\n        \"label\": \"Linear Equations Quiz\"\n      }\n    ],\n    \"default\": \"arithmetic\"\n  },\n  {\n    \"name\": \"arithmeticType\",\n    \"type\": \"select\",\n    \"label\": \"Arithmetic type\",\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"quizType\",\n          \"equals\": [\n            \"arithmetic\"\n          ]\n        }\n      ]\n    },\n    \"importance\": \"high\",\n    \"options\": [\n      {\n        \"value\": \"addition\",\n        \"label\": \"Addition\"\n      },\n      {\n        \"value\": \"subtraction\",\n        \"label\": \"Subtraction\"\n      },\n      {\n        \"value\": \"multiplication\",\n        \"label\": \"Multiplication\"\n      },\n      {\n        \"value\": \"division\",\n        \"label\": \"Division\"\n      }\n    ],\n    \"default\": \"addition\"\n  },\n  {\n    \"name\": \"equationType\",\n    \"type\": \"select\",\n    \"label\": \"Equation type\",\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"quizType\",\n          \"equals\": [\n            \"linearEquation\"\n          ]\n        }\n      ]\n    },\n    \"importance\": \"high\",\n    \"options\": [\n      {\n        \"value\": \"basic\",\n        \"label\": \"Basic [ 3x = 12 ]\"\n      },\n      {\n        \"value\": \"intermediate\",\n        \"label\": \"Intermediate [ 4x - 3 = 13 ]\"\n      },\n      {\n        \"value\": \"advanced\",\n        \"label\": \"Advanced [ 5x + 3 = 3x + 15 ]\"\n      }\n    ],\n    \"default\": \"intermediate\"\n  },\n  {\n    \"name\": \"useFractions\",\n    \"type\": \"boolean\",\n    \"label\": \"Enable fractions\",\n    \"description\": \"Enable to allow fractions in equations.\",\n    \"default\": false,\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"quizType\",\n          \"equals\": [\n            \"linearEquation\"\n          ]\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"maxQuestions\",\n    \"type\": \"number\",\n    \"label\": \"Max number of questions\",\n    \"importance\": \"medium\",\n    \"default\": 20,\n    \"min\": 2,\n    \"max\": 100\n  },\n  {\n    \"name\": \"UI\",\n    \"type\": \"group\",\n    \"label\": \"User interface translations\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"name\": \"score\",\n        \"type\": \"text\",\n        \"label\": \"Scoring during quiz\",\n        \"importance\": \"low\",\n        \"default\": \"Score:\"\n      },\n      {\n        \"name\": \"time\",\n        \"type\": \"text\",\n        \"label\": \"Time\",\n        \"importance\": \"low\",\n        \"default\": \"Time: @time\"\n      },\n      {\n        \"name\": \"resultPageHeader\",\n        \"type\": \"text\",\n        \"label\": \"Result page header\",\n        \"importance\": \"low\",\n        \"default\": \"Finished!\"\n      },\n      {\n        \"name\": \"go\",\n        \"type\": \"text\",\n        \"label\": \"Go label\",\n        \"importance\": \"low\",\n        \"default\": \"GO!\"\n      },\n      {\n        \"name\": \"startButton\",\n        \"type\": \"text\",\n        \"label\": \"Start button label\",\n        \"importance\": \"low\",\n        \"default\": \"Start\"\n      },\n      {\n        \"name\": \"retryButton\",\n        \"type\": \"text\",\n        \"label\": \"Retry button label\",\n        \"importance\": \"low\",\n        \"default\": \"Retry\"\n      },\n      {\n        \"name\": \"correctText\",\n        \"type\": \"text\",\n        \"label\": \"Readspeaker text for correct answer\",\n        \"importance\": \"low\",\n        \"default\": \"Correct\"\n      },\n      {\n        \"name\": \"incorrectText\",\n        \"type\": \"text\",\n        \"label\": \"Readspeaker text for incorrect answer\",\n        \"importance\": \"low\",\n        \"default\": \"Incorrect. Correct answer was :num\"\n      },\n      {\n        \"name\": \"durationLabel\",\n        \"type\": \"text\",\n        \"label\": \"Readspeaker label for the timer\",\n        \"importance\": \"low\",\n        \"default\": \"Duration in hours, minutes and seconds.\"\n      },\n      {\n        \"name\": \"humanizedQuestion\",\n        \"type\": \"text\",\n        \"label\": \"Readspeaker text for question\",\n        \"importance\": \"low\",\n        \"default\": \"What does :arithmetic equal?\"\n      },\n      {\n        \"name\": \"humanizedEquation\",\n        \"type\": \"text\",\n        \"label\": \"Readspeaker text for equation question\",\n        \"importance\": \"low\",\n        \"default\": \"For the equation :equation, what does :item equal?\"\n      },\n      {\n        \"name\": \"humanizedVariable\",\n        \"type\": \"text\",\n        \"label\": \"Readspeaker text for equation variable\",\n        \"importance\": \"low\",\n        \"default\": \"What does :item equal?\"\n      },\n      {\n        \"name\": \"plusOperator\",\n        \"type\": \"text\",\n        \"label\": \"Plus operator text\",\n        \"importance\": \"low\",\n        \"default\": \"plus\"\n      },\n      {\n        \"name\": \"subtractionOperator\",\n        \"type\": \"text\",\n        \"label\": \"Subtraction operator text\",\n        \"importance\": \"low\",\n        \"default\": \"minus\"\n      },\n      {\n        \"name\": \"multiplicationOperator\",\n        \"type\": \"text\",\n        \"label\": \"Multiplication operator text\",\n        \"importance\": \"low\",\n        \"default\": \"times\"\n      },\n      {\n        \"name\": \"divisionOperator\",\n        \"type\": \"text\",\n        \"label\": \"Division operator text\",\n        \"importance\": \"low\",\n        \"default\": \"delt p\"\n      },\n      {\n        \"name\": \"equalitySign\",\n        \"type\": \"text\",\n        \"label\": \"Equality sign text\",\n        \"importance\": \"low\",\n        \"default\": \"equals\"\n      },\n      {\n        \"name\": \"slideOfTotal\",\n        \"type\": \"text\",\n        \"label\": \"Slide number text\",\n        \"importance\": \"low\",\n        \"description\": \"Announces current slide and total number of slides, variables are :num and :total\",\n        \"default\": \"Slide :num of :total\"\n      }\n    ]\n  }\n]\n',NULL,NULL,NULL,NULL,'https://h5p.org/tutorial-arithmetic-quiz','https://h5p.org/arithmetic-quiz',1),(5,'H5PEditor.ShowWhen','Toggle visibility of a field based on rules',1,0,9,0,0,'','h5p-show-when.js','h5p-show-when.css','','',NULL,NULL,NULL,NULL,NULL,NULL,1),(6,'H5P.FontIcons','H5P.FontIcons',1,0,6,0,0,'','','styles/h5p-font-icons.css','','',NULL,NULL,NULL,NULL,NULL,NULL,1),(7,'H5P.JoubelUI','Joubel UI',1,3,18,0,0,'','js/joubel-help-dialog.js, js/joubel-message-dialog.js, js/joubel-progress-circle.js, js/joubel-simple-rounded-button.js, js/joubel-speech-bubble.js, js/joubel-throbber.js, js/joubel-tip.js, js/joubel-slider.js, js/joubel-score-bar.js, js/joubel-progressbar.js, js/joubel-ui.js','css/joubel-help-dialog.css, css/joubel-message-dialog.css, css/joubel-progress-circle.css, css/joubel-simple-rounded-button.css, css/joubel-speech-bubble.css, css/joubel-tip.css, css/joubel-slider.css, css/joubel-score-bar.css, css/joubel-progressbar.css, css/joubel-ui.css, css/joubel-icon.css','','',NULL,1,3,NULL,NULL,NULL,1),(8,'H5P.SoundJS','Sound js api',1,0,2,0,0,'','soundjs-0.6.2.min.js','','','',NULL,NULL,NULL,NULL,NULL,NULL,1),(9,'H5P.Transition','Transition',1,0,4,0,0,'','transition.js','','','',NULL,NULL,NULL,NULL,NULL,NULL,1),(10,'Odometer','Odometer',1,0,3,0,0,'','odometer.min.js','themes/odometer-theme-default.css','','',NULL,NULL,NULL,NULL,NULL,NULL,1),(11,'H5P.Chart','Chart',1,2,22,1,0,'iframe','chart.js, d3.js, pie.js, bar.js','chart.css','','[\n  {\n    \"name\": \"graphMode\",\n    \"type\": \"select\",\n    \"label\": \"Type of chart\",\n    \"importance\": \"high\",\n    \"options\": [\n      {\n        \"value\": \"pieChart\",\n        \"label\": \"Pie Chart\"\n      },\n      {\n        \"value\": \"barChart\",\n        \"label\": \"Bar Chart\"\n      }\n    ],\n    \"default\": \"pieChart\"\n  },\n  {\n    \"name\": \"listOfTypes\",\n    \"type\": \"list\",\n    \"label\": \"Data elements\",\n    \"importance\": \"high\",\n    \"entity\": \"option\",\n    \"min\": 1,\n    \"defaultNum\": 2,\n    \"field\": {\n      \"name\": \"type\",\n      \"type\": \"group\",\n      \"label\": \"Data element\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"text\",\n          \"type\": \"text\",\n          \"label\": \"Name\",\n          \"importance\": \"medium\"\n        },\n        {\n          \"name\": \"value\",\n          \"type\": \"number\",\n          \"label\": \"Value\",\n          \"importance\": \"low\",\n          \"default\": 1,\n          \"min\": 0.0001,\n          \"decimals\": 4\n        },\n        {\n          \"name\": \"color\",\n          \"type\": \"text\",\n          \"widget\": \"colorSelector\",\n          \"label\": \"Color\",\n          \"importance\": \"low\",\n          \"default\": \"#000\",\n          \"optional\": true,\n          \"spectrum\": {\n            \"showInput\": true,\n            \"preferredFormat\": \"hex\"\n          }\n        },\n        {\n          \"name\": \"fontColor\",\n          \"type\": \"text\",\n          \"widget\": \"colorSelector\",\n          \"label\": \"Font Color\",\n          \"importance\": \"low\",\n          \"default\": \"#fff\",\n          \"optional\": true,\n          \"spectrum\": {\n            \"showInput\": true,\n            \"preferredFormat\": \"hex\"\n          }\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"figureDefinition\",\n    \"type\": \"text\",\n    \"label\": \"Text read by readspeakers defining the figure as a chart.\",\n    \"importance\": \"low\",\n    \"default\": \"Chart\",\n    \"common\": true\n  }\n]\n',NULL,1,21,NULL,'https://h5p.org/tutorial-chart','https://h5p.org/chart',1),(12,'H5PEditor.ColorSelector','H5PEditor.ColorSelector',1,3,1,0,0,'','scripts/spectrum.js, scripts/color-selector.js','styles/spectrum.css, styles/color-selector.css','','',NULL,1,24,NULL,NULL,NULL,1),(13,'H5P.Collage','Collage',0,3,17,1,0,'','collage.js, template.js, clip.js','collage.css','','[\n  {\n    \"name\": \"collage\",\n    \"label\": \"Preview\",\n    \"importance\": \"high\",\n    \"type\": \"group\",\n    \"widget\": \"collage\",\n    \"description\": \"You can move(pan) the images around by dragging them. You can also select an image and then use the + or - keys on your keyboard to zoom or simply hold down the Z key while moving your mouse wheel.\",\n    \"fields\": [\n      {\n        \"name\": \"template\",\n        \"label\": \"Layout\",\n        \"importance\": \"high\",\n        \"type\": \"select\",\n        \"options\": [\n          {\n            \"value\": \"1\",\n            \"label\": \"1\"\n          },\n          {\n            \"value\": \"1-1\",\n            \"label\": \"1-1\"\n          },\n          {\n            \"value\": \"2\",\n            \"label\": \"2\"\n          },\n          {\n            \"value\": \"2-1\",\n            \"label\": \"2-1\"\n          },\n          {\n            \"value\": \"1-2\",\n            \"label\": \"1-2\"\n          },\n          {\n            \"value\": \"2-2\",\n            \"label\": \"2-2\"\n          },\n          {\n            \"value\": \"3-1\",\n            \"label\": \"3-1\"\n          },\n          {\n            \"value\": \"1-3\",\n            \"label\": \"1-3\"\n          },\n          {\n            \"value\": \"2-3\",\n            \"label\": \"2-3\"\n          },\n          {\n            \"value\": \"3-2\",\n            \"label\": \"3-2\"\n          },\n          {\n            \"value\": \"3-3\",\n            \"label\": \"3-3\"\n          }\n        ],\n        \"default\": \"2-1\"\n      },\n      {\n        \"name\": \"options\",\n        \"label\": \"Display options\",\n        \"importance\": \"low\",\n        \"type\": \"group\",\n        \"fields\": [\n          {\n            \"name\": \"heightRatio\",\n            \"label\": \"Height\",\n            \"importance\": \"low\",\n            \"type\": \"number\",\n            \"decimals\": 2,\n            \"min\": 0.1,\n            \"max\": 2,\n            \"default\": 0.75\n          },\n          {\n            \"name\": \"spacing\",\n            \"label\": \"Spacing\",\n            \"importance\": \"low\",\n            \"type\": \"number\",\n            \"decimals\": 2,\n            \"min\": 0,\n            \"max\": 2,\n            \"default\": 0.5\n          },\n          {\n            \"name\": \"frame\",\n            \"label\": \"Frame\",\n            \"importance\": \"low\",\n            \"type\": \"boolean\",\n            \"default\": true\n          }\n        ]\n      },\n      {\n        \"name\": \"clips\",\n        \"label\": \"Clips\",\n        \"importance\": \"low\",\n        \"type\": \"list\",\n        \"min\": 1,\n        \"entity\": \"clip\",\n        \"field\": {\n          \"name\": \"clip\",\n          \"label\": \"Clip\",\n          \"importance\": \"low\",\n          \"type\": \"group\",\n          \"fields\": [\n            {\n              \"name\": \"image\",\n              \"type\": \"image\",\n              \"label\": \"Image\",\n              \"importance\": \"low\"\n            },\n            {\n              \"name\": \"offset\",\n              \"label\": \"Offset\",\n              \"importance\": \"low\",\n              \"type\": \"group\",\n              \"fields\": [\n                {\n                  \"name\": \"top\",\n                  \"label\": \"Top\",\n                  \"importance\": \"low\",\n                  \"type\": \"number\",\n                  \"default\": 0\n                },\n                {\n                  \"name\": \"left\",\n                  \"label\": \"Left\",\n                  \"importance\": \"low\",\n                  \"type\": \"number\",\n                  \"default\": 0\n                }\n              ]\n            },\n            {\n              \"name\": \"alt\",\n              \"type\": \"text\",\n              \"label\": \"Alternative text\",\n              \"importance\": \"high\",\n              \"description\": \"Required. If the browser can\'t load the image this text will be displayed instead. Also used by readspeakers.\"\n            },\n            {\n              \"name\": \"title\",\n              \"type\": \"text\",\n              \"label\": \"Hover text\",\n              \"importance\": \"low\",\n              \"description\": \"Optional. This text is displayed when the user hovers his pointing device over the image.\",\n              \"optional\": true\n            },\n            {\n              \"name\": \"scale\",\n              \"label\": \"Scale\",\n              \"importance\": \"low\",\n              \"type\": \"number\",\n              \"decimals\": 2,\n              \"min\": 0.01,\n              \"default\": 1\n            }\n          ]\n        }\n      }\n    ]\n  }\n]\n',NULL,1,7,NULL,'https://h5p.org/tutorial-collage','https://h5p.org/collage',1),(14,'H5PEditor.Collage','Collage Editor',0,3,19,0,0,'','collage-editor.js, layout-selector.js, clip-editor.js','collage-editor.css','','',NULL,1,24,NULL,NULL,NULL,1),(15,'H5P.Audio','Audio',1,5,3,1,0,'iframe','scripts/audio.js','styles/audio.css','','[\n  {\n    \"name\": \"files\",\n    \"type\": \"audio\",\n    \"importance\": \"high\",\n    \"label\": \"Source files\",\n    \"disableCopyright\": true\n  },\n  {\n    \"name\": \"playerMode\",\n    \"type\": \"select\",\n    \"importance\": \"low\",\n    \"label\": \"Player mode\",\n    \"description\": \"Select the layout of the player.\",\n    \"options\": [\n      {\n        \"value\": \"minimalistic\",\n        \"label\": \"Minimalistic\"\n      },\n      {\n        \"value\": \"full\",\n        \"label\": \"Full\"\n      },\n      {\n        \"value\": \"transparent\",\n        \"label\": \"Transparent\"\n      }\n    ],\n    \"default\": \"minimalistic\"\n  },\n  {\n    \"name\": \"fitToWrapper\",\n    \"type\": \"boolean\",\n    \"importance\": \"low\",\n    \"label\": \"Fit to wrapper\",\n    \"default\": false,\n    \"descriptions\": \"Adjust audioplayer size to use available space\",\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"playerMode\",\n          \"equals\": \"minimalistic\"\n        },\n        {\n          \"field\": \"playerMode\",\n          \"equals\": \"full\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"controls\",\n    \"type\": \"boolean\",\n    \"importance\": \"low\",\n    \"label\": \"Enable controls\",\n    \"default\": true,\n    \"description\": \"Controls allow the user to for instance pause the audio\",\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"playerMode\",\n          \"equals\": \"full\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"autoplay\",\n    \"type\": \"boolean\",\n    \"importance\": \"low\",\n    \"label\": \"Enable autoplay\",\n    \"description\": \"With autoplay the audio starts to play immediately. Do note that this is not supported by all browsers\"\n  },\n  {\n    \"name\": \"playAudio\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Play audio (Readspeaker)\",\n    \"common\": true,\n    \"default\": \"Play audio\"\n  },\n  {\n    \"name\": \"pauseAudio\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Pause audio (Readspeaker)\",\n    \"common\": true,\n    \"default\": \"Pause audio\"\n  },\n  {\n    \"name\": \"contentName\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Audio content name\",\n    \"common\": true,\n    \"default\": \"Audio\"\n  },\n  {\n    \"name\": \"audioNotSupported\",\n    \"type\": \"text\",\n    \"label\": \"Audio not supported message\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"Your browser does not support this audio\"\n  }\n]\n',NULL,1,19,NULL,NULL,NULL,1),(16,'H5P.AudioRecorder','Audio Recorder',1,0,32,1,0,'iframe','dist/h5p-audio-recorder.js','fonts/h5p-audio-recorder-font-open-sans.css','','[\n  {\n    \"label\": \"Task Description\",\n    \"importance\": \"high\",\n    \"name\": \"title\",\n    \"type\": \"text\",\n    \"widget\": \"textarea\",\n    \"description\": \"Optional text to display above the audio recorder\",\n    \"optional\": true\n  },\n  {\n    \"label\": \"Localization\",\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"name\": \"