,\n      \"code\"\n    ]\n  },\n  {\n    \"name\": \"dialogs\",\n    \"type\": \"list\",\n    \"importance\": \"high\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"label\": \"Dialogs\",\n    \"entity\": \"dialog\",\n    \"min\": 1,\n    \"defaultNum\": 1,\n    \"field\": {\n      \"name\": \"question\",\n      \"type\": \"group\",\n      \"label\": \"Question\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"text\",\n          \"type\": \"text\",\n          \"widget\": \"html\",\n          \"tags\": [\n            \"p\",\n            \"br\",\n            \"strong\",\n            \"em\",\n            \"code\"\n          ],\n          \"label\": \"Text\",\n          \"importance\": \"high\",\n          \"description\": \"Hint for the first part of the dialogue\",\n          \"default\": \"<p style=\\\"text-align: center;\\\"></p>\"\n        },\n        {\n          \"name\": \"answer\",\n          \"type\": \"text\",\n          \"widget\": \"html\",\n          \"tags\": [\n            \"p\",\n            \"br\",\n            \"strong\",\n            \"em\",\n            \"code\"\n          ],\n          \"label\": \"Answer\",\n          \"importance\": \"high\",\n          \"description\": \"Hint for the second part of the dialogue\",\n          \"default\": \"<p style=\\\"text-align: center;\\\"></p>\"\n        },\n        {\n          \"name\": \"image\",\n          \"type\": \"image\",\n          \"label\": \"Image\",\n          \"importance\": \"high\",\n          \"optional\": true,\n          \"description\": \"Optional image for the card. (The card may use just an image, just a text or both)\"\n        },\n        {\n          \"name\": \"imageAltText\",\n          \"type\": \"text\",\n          \"label\": \"Alternative text for the image\",\n          \"importance\": \"high\",\n          \"optional\": true\n        },\n        {\n          \"n