\n    \"fields\": [\n      {\n        \"name\": \"settings\",\n        \"type\": \"group\",\n        \"label\": \"Settings\",\n        \"importance\": \"high\",\n        \"fields\": [\n          {\n            \"name\": \"background\",\n            \"type\": \"image\",\n            \"label\": \"Background image\",\n            \"importance\": \"low\",\n            \"optional\": true,\n            \"description\": \"Optional. Select an image to use as background for your drag and drop task.\"\n          },\n          {\n            \"name\": \"size\",\n            \"type\": \"group\",\n            \"widget\": \"dimensions\",\n            \"label\": \"Task size\",\n            \"importance\": \"low\",\n            \"description\": \"Specify how large (in px) the play area should be.\",\n            \"default\": {\n              \"width\": 620,\n              \"height\": 310,\n              \"field\": \"background\"\n            },\n            \"fields\": [\n              {\n                \"name\": \"width\",\n                \"type\": \"number\"\n              },\n              {\n                \"name\": \"height\",\n                \"type\": \"number\"\n              }\n            ]\n          }\n        ]\n      },\n      {\n        \"name\": \"task\",\n        \"type\": \"group\",\n        \"widget\": \"dragQuestion\",\n        \"label\": \"Task\",\n        \"importance\": \"high\",\n        \"description\": \"Start by placing your drop zones.<br/>Next, place your droppable elements and check off the appropriate drop zones.<br/>Last, edit your drop zone again and check off the correct answers.\",\n        \"fields\": [\n          {\n            \"name\": \"elements\",\n            \"type\": \"list\",\n            \"label\": \"Elements\",\n            \"importance\": \"high\",\n            \"entity\": \"element\",\n            \"field\": {\n              \"type\": \"group\",\n              \"label\": \"Element\",\n              \"importance\": \"high\",\n              \"fields\": [\n                {\n                  \"name\": \"type\",\n                  \"type\": \"library\",\n                  \"description\": \"Choose the type of content you would like to add.\",\n                  \"importance\": \"medium\",\n                  \"options\": [\n                    \"H5P.AdvancedText 1.1\",\n                    \"H5P.Image 1.1\"\n                  ]\n                },\n                {\n                  \"name\": \"x\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"y\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"height\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"width\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"dropZones\",\n                  \"type\": \"select\",\n                  \"widget\": \"dynamicCheckboxes\",\n                  \"label\": \"Select drop zones\",\n                  \"importance\": \"high\",\n                  \"multiple\": true\n                },\n                {\n                  \"name\": \"backgroundOpacity\",\n                  \"type\": \"number\",\n                  \"label\": \"Background Opacity\",\n                  \"importance\": \"low\",\n                  \"min\": 0,\n                  \"max\": 100,\n                  \"step\": 5,\n                  \"default\": 100,\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"multiple\",\n                  \"type\": \"boolean\",\n                  \"label\": \"Infinite number of element instances\",\n                  \"importance\": \"low\",\n                  \"description\": \"Clones this element so that it can be dragged to multiple drop zones.\",\n                  \"default\": false\n                }\n              ]\n            }\n          },\n          {\n            \"name\": \"dropZones\",\n            \"type\": \"list\",\n            \"label\": \"Drop Zones\",\n            \"importance\": \"high\",\n            \"entity\": \"Drop Zone\",\n            \"field\": {\n              \"type\": \"group\",\n              \"label\": \"Drop Zone\",\n              \"importance\": \"high\",\n              \"fields\": [\n                {\n                  \"name\": \"label\",\n                  \"type\": \"text\",\n                  \"widget\": \"html\",\n                  \"label\": \"Label\",\n                  \"importance\": \"medium\",\n                  \"enterMode\": \"div\",\n                  \"tags\": [\n                    \"strong\",\n                    \"em\",\n                    \"del\",\n                    \"code\"\n                  ]\n                },\n                {\n                  \"name\": \"showLabel\",\n                  \"type\": \"boolean\",\n                  \"label\": \"Show label\",\n                  \"importance\": \"low\"\n                },\n                {\n                  \"name\": \"x\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"y\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"height\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"width\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"correctElements\",\n                  \"type\": \"select\",\n                  \"widget\": \"dynamicCheckboxes\",\n                  \"label\": \"Select correct elements\",\n                  \"importance\": \"low\",\n                  \"multiple\": true\n                },\n                {\n                  \"name\": \"backgroundOpacity\",\n                  \"type\": \"number\",\n                  \"label\": \"Background Opacity\",\n                  \"importance\": \"low\",\n                  \"min\": 0,\n                  \"max\": 100,\n                  \"step\": 5,\n                  \"default\": 100,\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"tipsAndFeedback\",\n                  \"type\": \"group\",\n                  \"label\": \"Tips and feedback\",\n                  \"importance\": \"low\",\n                  \"optional\": true,\n                  \"fields\": [\n                    {\n                      \"name\": \"tip\",\n                      \"label\": \"Tip text\",\n                      \"importance\": \"low\",\n                      \"type\": \"text\",\n                      \"widget\": \"html\",\n                      \"tags\": [\n                        \"p\",\n                        \"br\",\n                        \"strong\",\n                        \"em\",\n                        \"code\"\n                      ],\n                      \"optional\": true\n                    },\n                    {\n                      \"name\": \"feedbackOnCorrect\",\n                      \"type\": \"text\",\n                      \"label\": \"Message displayed on correct match\",\n                      \"importance\": \"low\",\n                      \"description\": \"Message will appear below the task on \\\"check\\\" if correct droppable is matched.\",\n                      \"optional\": true\n                    },\n                    {\n                      \"name\": \"feedbackOnIncorrect\",\n                      \"type\": \"text\",\n                      \"label\": \"Message displayed on incorrect match\",\n                      \"importance\": \"low\",\n                      \"description\": \"Message will appear below the task on \\\"check\\\" if the match is incorrect.\",\n                      \"optional\": true\n                    }\n                  ]\n                },\n                {\n                  \"name\": \"single\",\n                  \"type\": \"boolean\",\n                  \"label\": \"This drop zone can only contain one element\",\n                  \"description\": \"Make sure there is only one correct answer for this dropzone\",\n                  \"importance\": \"low\",\n                  \"default\": false\n                },\n                {\n                  \"name\": \"autoAlign\",\n                  \"type\": \"boolean\",\n                  \"label\": \"Enable Auto-Align\",\n                  \"importance\": \"low\",\n                  \"description\": \"Will auto-align all draggables dropped in this zone.\"\n                }\n              ]\n            }\n          }\n        ]\n      }\n    ]\n  },\n  {\n    \"name\": \"overallFeedback\",\n    \"type\": \"group\",\n    \"label\": \"Overall Feedback\",\n    \"importance\": \"low\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"overallFeedback\",\n        \"type\": \"list\",\n        \"widgets\": [\n          {\n            \"name\": \"RangeList\",\n            \"label\": \"Default\"\n          }\n        ],\n        \"importance\": \"high\",\n        \"label\": \"Define custom feedback for any score range\",\n        \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n        \"entity\": \"range\",\n        \"min\": 1,\n        \"defaultNum\": 1,\n        \"optional\": true,\n        \"field\": {\n          \"name\": \"overallFeedback\",\n          \"type\": \"group\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"from\",\n              \"type\": \"number\",\n              \"label\": \"Score Range\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 0,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"to\",\n              \"type\": \"number\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 100,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"feedback\",\n              \"type\": \"text\",\n              \"label\": \"Feedback for defined score range\",\n              \"importance\": \"low\",\n              \"placeholder\": \"Fill in the feedback\",\n              \"optional\": true\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"enableRetry\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Retry\\\"\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"enableCheckButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Check\\\" button\",\n        \"widget\": \"none\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"singlePoint\",\n        \"type\": \"boolean\",\n        \"label\": \"Give one point for the whole task\",\n        \"importance\": \"low\",\n        \"description\": \"Disable to give one point for each draggable that is placed correctly.\",\n        \"default\": false\n      },\n      {\n        \"label\": \"Apply penalties\",\n        \"name\": \"applyPenalties\",\n        \"type\": \"boolean\",\n        \"description\": \"Apply penalties for elements dropped in the wrong drop zones. This must be enabled when the same element(s) are able to be dropped into multiple drop zones, or if there is only one drop-zone. If this is not enabled, learners may match all items to all drop-zones and always receive a full score.\",\n        \"default\": true\n      },\n      {\n        \"name\": \"enableScoreExplanation\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable score explanation\",\n        \"description\": \"Display a score explanation to user when checking their answers (if the \'Apply penalties\' option has been selected).\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"singlePoint\",\n              \"equals\": false\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"backgroundOpacity\",\n        \"type\": \"text\",\n        \"label\": \"Background opacity for draggables\",\n        \"importance\": \"low\",\n        \"description\": \"If this field is set, it will override opacity set on all draggable elements. This should be a number between 0 and 100, where 0 means full transparency and 100 means no transparency\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"dropZoneHighlighting\",\n        \"type\": \"select\",\n        \"label\": \"Drop Zone Highlighting\",\n        \"importance\": \"low\",\n        \"description\": \"Choose when to highlight drop zones.\",\n        \"default\": \"dragging\",\n        \"options\": [\n          {\n            \"value\": \"dragging\",\n            \"label\": \"When dragging\"\n          },\n          {\n            \"value\": \"always\",\n            \"label\": \"Always\"\n          },\n          {\n            \"value\": \"never\",\n            \"label\": \"Never\"\n          }\n        ]\n      },\n      {\n        \"name\": \"autoAlignSpacing\",\n        \"type\": \"number\",\n        \"label\": \"Spacing for Auto-Align (in px)\",\n        \"importance\": \"low\",\n        \"min\": 0,\n        \"default\": 2,\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableFullScreen\",\n        \"label\": \"Enable FullScreen\",\n        \"importance\": \"low\",\n        \"type\": \"boolean\",\n        \"description\": \"Check this option to enable the full screen button.\",\n        \"default\": false\n      },\n      {\n        \"name\": \"showScorePoints\",\n        \"type\": \"boolean\",\n        \"label\": \"Show score points\",\n        \"description\": \"Show points earned for each answer. Not available when the \'Give one point for the whole task\' option is enabled.\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"showTitle\",\n        \"type\": \"boolean\",\n        \"label\": \"Show Title\",\n        \"importance\": \"low\",\n        \"description\": \"Uncheck this option if you do not want this title to be displayed. The title will only be displayed in summaries, statistics etc.\",\n        \"default\": true\n      }\n    ]\n  },\n  {\n    \"name\": \"localize\",\n    \"type\": \"group\",\n    \"label\": \"Localize\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"name\": \"fullscreen\",\n        \"type\": \"text\",\n        \"label\": \"Fullscreen label\",\n        \"default\": \"Fullscreen\"\n      },\n      {\n        \"name\": \"exitFullscreen\",\n        \"type\": \"text\",\n        \"label\": \"Exit fullscreen label\",\n        \"default\": \"Exit fullscreen\"\n      }\n    ]\n  },\n  {\n    \"name\": \"grabbablePrefix\",\n    \"type\": \"text\",\n    \"label\": \"Grabbable prefix\",\n    \"importance\": \"low\",\n    \"default\": \"Grabbable {num} of {total}.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"grabbableSuffix\",\n    \"type\": \"text\",\n    \"label\": \"Grabbable suffix\",\n    \"importance\": \"low\",\n    \"default\": \"Placed in dropzone {num}.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"dropzonePrefix\",\n    \"type\": \"text\",\n    \"label\": \"Dropzone prefix\",\n    \"importance\": \"low\",\n    \"default\": \"Dropzone {num} of {total}.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"noDropzone\",\n    \"type\": \"text\",\n    \"label\": \"No dropzone selection label\",\n    \"importance\": \"low\",\n    \"default\": \"No dropzone.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"tipLabel\",\n    \"type\": \"text\",\n    \"label\": \"Label for show tip button\",\n    \"importance\": \"low\",\n    \"default\": \"Show tip.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"tipAvailable\",\n    \"type\": \"text\",\n    \"label\": \"Label for tip available\",\n    \"importance\": \"low\",\n    \"default\": \"Tip available\",\n    \"common\": true\n  },\n  {\n    \"name\": \"correctAnswer\",\n    \"type\": \"text\",\n    \"label\": \"Label for correct answer\",\n    \"importance\": \"low\",\n    \"default\": \"Correct answer\",\n    \"common\": true\n  },\n  {\n    \"name\": \"wrongAnswer\",\n    \"type\": \"text\",\n    \"label\": \"Label for incorrect answer\",\n    \"importance\": \"low\",\n    \"default\": \"Wrong answer\",\n    \"common\": true\n  },\n  {\n    \"name\": \"feedbackHeader\",\n    \"type\": \"text\",\n    \"label\": \"Header for panel containing feedback for correct/incorrect answers\",\n    \"importance\": \"low\",\n    \"default\": \"Feedback\",\n    \"common\": true\n  },\n  {\n    \"name\": \"scoreBarLabel\",\n    \"type\": \"text\",\n    \"label\": \"Textual representation of the score bar for those using a readspeaker\",\n    \"default\": \"You got :num out of :total points\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"scoreExplanationButtonLabel\",\n    \"type\