       ]\n                }\n              ]\n            }\n          },\n          {\n            \"name\": \"noneSelectedFeedback\",\n            \"type\": \"text\",\n            \"label\": \"Feedback if the user selects an empty spot:\",\n            \"importance\": \"low\",\n            \"placeholder\": \"You didn\'t locate any hotspots, try again!\",\n            \"optional\": true\n          },\n          {\n            \"name\": \"showFeedbackAsPopup\",\n            \"type\": \"boolean\",\n            \"label\": \"Show feedback as a popup\",\n            \"importance\": \"low\",\n            \"default\": true,\n            \"optional\": true\n          },\n          {\n            \"label\": \"Localization\",\n            \"name\": \"l10n\",\n            \"type\": \"group\",\n            \"fields\": [\n              {\n                \"name\": \"retryText\",\n                \"label\": \"Retry button text\",\n                \"type\": \"text\",\n                \"default\": \"Retry\",\n                \"optional\": true\n              },\n              {\n                \"name\": \"closeText\",\n                \"label\": \"Close button text\",\n                \"type\": \"text\",\n                \"default\": \"Close\",\n                \"optional\": true\n              }\n            ]\n          }\n        ]\n      }\n    ]\n  },\n  {\n    \"name\": \"scoreBarLabel\",\n    \"type\": \"text\",\n    \"label\": \"Textual representation of the score bar for those using a readspeaker\",\n    \"default\": \"You got :num out of :total points\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yRetry\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for \\\"Retry\\\" button\",\n    \"default\": \"Retry the task. Reset all responses and start the task over again.\",\n    \"importance\": \"low\",\n    \"common\": true\n  }\n]',NULL,1,23,NULL,NULL,NULL,1),(59,'H5P.ImageHotspots','Image Hotspots',1,10,2