",\n    \"type\": \"image\",\n    \"label\": \"Uploaded image\",\n    \"optional\": false,\n    \"description\": \"Use your own image for the hotspot icon.<br />75px by 75px is recommended for your image.\",\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"iconType\",\n          \"equals\": [\n            \"image\"\n          ]\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"color\",\n    \"type\": \"text\",\n    \"label\": \"Hotspot color\",\n    \"importance\": \"medium\",\n    \"description\": \"The color of the hotspots\",\n    \"optional\": true,\n    \"default\": \"#981d99\",\n    \"widget\": \"showWhen\",\n    \"spectrum\": {\n      \"showInput\": true\n    },\n    \"showWhen\": {\n      \"widget\": \"colorSelector\",\n      \"rules\": [\n        {\n          \"field\": \"iconType\",\n          \"equals\": [\n            \"icon\"\n          ]\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"hotspots\",\n    \"type\": \"list\",\n    \"entity\": \"hotspot\",\n    \"label\": \"Hotspots\",\n    \"importance\": \"high\",\n    \"min\": 1,\n    \"defaultNum\": 1,\n    \"field\": {\n      \"name\": \"hotspot\",\n      \"type\": \"group\",\n      \"label\": \"Hotspot\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"position\",\n          \"type\": \"group\",\n          \"widget\": \"imageCoordinateSelector\",\n          \"imageFieldPath\": \"../../image\",\n          \"label\": \"Hotspot position\",\n          \"importance\": \"high\",\n          \"description\": \"Click on the thumbnail image to place the hotspot\",\n          \"fields\": [\n            {\n              \"name\": \"x\",\n              \"type\": \"number\"\n            },\n            {\n              \"name\": \"y\",\n              \"type\": \"number\"\n            },\n            {\n              \"name\": \"legacyPositioning\",\n              \"type\": \"boolean\"\n            }\n          ]\n        },\n        {\n          \"name\": \"alwaysFullscreen\",\n          \"type\": \"boolean\",\n          \"label\": \"Cover entire background image\",\n          \"importance\": \"low\",\n          \"description\": \"When the user clicks the hotspot the popup will cover the entire background image\"\n        },\n        {\n          \"name\": \"header\",\n          \"type\": \"text\",\n          \"label\": \"Header\",\n          \"importance\": \"low\",\n          \"description\": \"Optional header for the popup\",\n          \"optional\": true\n        },\n        {\n          \"name\": \"content\",\n          \"type\": \"list\",\n          \"label\": \"Popup content\",\n          \"importance\": \"medium\",\n          \"field\": {\n            \"name\": \"action\",\n            \"type\": \"library\",\n            \"label\": \"Content Item\",\n            \"options\": [\n              \"H5P.Text 1.1\",\n              \"H5P.Video 1.6\",\n              \"H5P.Image 1.1\",\n              \"H5P.Audio 1.5\"\n            ]\n          }\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"hotspotNumberLabel\",\n    \"type\": \"text\",\n    \"label\": \"Hotspot label for assistive technologies\",\n    \"default\": \"Hotspot #num\",\n    \"description\": \"Will help announce what hotspot element has been navigated to if there is no header specified for a hotspot. #num can be used to replace the hotspot number.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"closeButtonLabel\",\n    \"type\": \"text\",\n    \"label\": \"Close button label for assistive technologies\",\n    \"default\": \"Close\",\n    \"common\": true\n  }\n]',NULL,1,19,NULL,NULL,NULL,1),(60,'H5P.InteractiveVideo','Interactive Video',1,26,6,1,1,'iframe','dist/h5p-interactive-video.js','dist/h5p-interactive-video.css','','[\n  {\n    \"name\": \"interactiveVideo\",\n    \"type\": \"group\",\n    \"widget\": \"wizard\",\n    \"label\": \"Interactive Video Editor\",\n    \"importance\": \"high\