onal\": true,\n        \"description\": \"Start playing the video automatically\"\n      },\n      {\n        \"name\": \"loop\",\n        \"type\": \"boolean\",\n        \"label\": \"Loop the video\",\n        \"default\": false,\n        \"optional\": true,\n        \"description\": \"Check if video should run in a loop\"\n      },\n      {\n        \"name\": \"showSolutionButton\",\n        \"type\": \"select\",\n        \"label\": \"Override \\\"Show Solution\\\" button\",\n        \"importance\": \"low\",\n        \"description\": \"This option determines if the \\\"Show Solution\\\" button will be shown for all questions, disabled for all or configured for each question individually.\",\n        \"optional\": true,\n        \"options\": [\n          {\n            \"value\": \"on\",\n            \"label\": \"Enabled\"\n          },\n          {\n            \"value\": \"off\",\n            \"label\": \"Disabled\"\n          }\n        ]\n      },\n      {\n        \"name\": \"retryButton\",\n        \"type\": \"select\",\n        \"label\": \"Override \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"description\": \"This option determines if the \\\"Retry\\\" button will be shown for all questions, disabled for all or configured for each question individually.\",\n        \"options\": [\n          {\n            \"value\": \"on\",\n            \"label\": \"Enabled\"\n          },\n          {\n            \"value\": \"off\",\n            \"label\": \"Disabled\"\n          }\n        ]\n      },\n      {\n        \"name\": \"showBookmarksmenuOnLoad\",\n        \"type\": \"boolean\",\n        \"label\": \"Start with bookmarks menu open\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"description\": \"This function is not available on iPad when using YouTube as video source.\"\n      },\n      {\n        \"name\": \"showRewind10\",\n        \"type\": \"boolean\",\n        \"label\": \"Show button for rewinding 10 se