\": \"Solution mode header for assistive technologies\",\n    \"default\": \"Solution mode\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yCheckingHeader\",\n    \"type\": \"text\",\n    \"label\": \"Checking mode header for assistive technologies\",\n    \"default\": \"Checking mode\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yCheck\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for \\\"Check\\\" button\",\n    \"default\": \"Check the answers. The responses will be marked as correct, incorrect, or unanswered.\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yShowSolution\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for \\\"Show Solution\\\" button\",\n    \"default\": \"Show the solution. The task will be marked with its correct solution.\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yRetry\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for \\\"Retry\\\" button\",\n    \"default\": \"Retry the task. Reset all responses and start the task over again.\",\n    \"importance\": \"low\",\n    \"common\": true\n  }\n]',NULL,1,19,NULL,NULL,NULL,1),(64,'H5P.MaterialDesignIcons','Material Design Icons',1,0,0,0,0,'','','h5p-material-icons.css','','',NULL,NULL,NULL,NULL,NULL,NULL,1),(65,'H5P.MemoryGame','Memory Game',1,3,11,1,0,'','memory-game.js, card.js, counter.js, popup.js, timer.js','memory-game.css','','[\n  {\n    \"name\": \"cards\",\n    \"type\": \"list\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"label\": \"Cards\",\n    \"importance\": \"high\",\n    \"entity\": \"card\",\n    \"min\": 2,\n    \"max\": 100,\n    \"field\": {\n      \"type\": \"group\",\n      \"name\": \"card\",\n      \"label\": \"Card\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"image\",\n          \"type\": \"image\",\n          \"label\": \"Image\",\n          \"importance\": \"high\",\n          \"ratio\": 1\n        },\n        {\n          \"name\": \"imageAlt\",\n          \"type\": \"text\",\n          \"label\": \"Alternative text for Image\",\n          \"importance\": \"high\",\n          \"description\": \"Describe what can be seen in the photo. The text is read by text-to-speech tools needed by visually impaired users.\"\n        },\n        {\n          \"name\": \"audio\",\n          \"type\": \"audio\",\n          \"importance\": \"high\",\n          \"label\": \"Audio Track\",\n          \"description\": \"An optional sound that plays when the card is turned.\",\n          \"optional\": true,\n          \"widgetExtensions\": [\"AudioRecorder\"]\n        },\n        {\n          \"name\": \"match\",\n          \"type\": \"image\",\n          \"label\": \"Matching Image\",\n          \"importance\": \"low\",\n          \"optional\": true,\n          \"description\": \"An optional image to match against instead of using two cards with the same image.\",\n          \"ratio\": 1\n        },\n        {\n          \"name\": \"matchAlt\",\n          \"type\": \"text\",\n          \"label\": \"Alternative text for Matching Image\",\n          \"importance\": \"low\",\n          \"optional\": true,\n          \"description\": \"Describe what can be seen in the photo. The text is read by text-to-speech tools needed by visually impaired users.\"\n        },\n        {\n          \"name\": \"matchAudio\",\n          \"type\": \"audio\",\n          \"importance\": \"low\",\n          \"label\": \"Matching Audio Track\",\n          \"description\": \"An optional sound that plays when the second card is turned.\",\n          \"optional\": true,\n          \"widgetExtensions\": [\"AudioRecorder\"]\n        },\n        {\n          \"name\": \"description\",\n          \"type\": \"text\",\n          \"label\": \"Description\",\n          \"importance\": \"low\",\n          \"maxLength\": 150,\n          \"optional\": true,\n          \"description\": \"An optional short text that will pop up once the two matching cards are found.\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the game behaves.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"useGrid\",\n        \"type\": \"boolean\",\n        \"label\": \"Position the cards in a square\",\n        \"description\": \"Will try to match the number of columns and rows when laying out the cards. Afterward, the cards will be scaled to fit the container.\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"numCardsToUse\",\n        \"type\": \"number\",\n        \"label\": \"Number of cards to use\",\n        \"description\": \"Setting this to a number greater than 2 will make the game pick random cards from the list of cards.\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"min\": 2\n      },\n      {\n        \"name\": \"allowRetry\",\n        \"type\": \"boolean\",\n        \"label\": \"Add button for retrying when the game is over\",\n        \"importance\": \"low\",\n        \"default\": true\n      }\n    ]\n  },\n  {\n    \"name\": \"lookNFeel\",\n    \"type\": \"group\",\n    \"label\": \"Look and feel\",\n    \"importance\": \"low\",\n    \"description\": \"Control the visuals of the game.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"themeColor\",\n        \"type\": \"text\",\n        \"label\": \"Theme Color\",\n        \"importance\": \"low\",\n        \"description\": \"Choose a color to create a theme for your card game.\",\n        \"optional\": true,\n        \"default\