allFeedback\",\n        \"type\": \"group\",\n        \"label\": \"Overall Feedback\",\n        \"importance\": \"low\",\n        \"expanded\": true,\n        \"fields\": [\n          {\n            \"name\": \"overallFeedback\",\n            \"type\": \"list\",\n            \"widgets\": [\n              {\n                \"name\": \"RangeList\",\n                \"label\": \"Default\"\n              }\n            ],\n            \"importance\": \"high\",\n            \"label\": \"Define custom feedback for any score range\",\n            \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n            \"entity\": \"range\",\n            \"min\": 1,\n            \"defaultNum\": 1,\n            \"optional\": true,\n            \"field\": {\n              \"name\": \"overallFeedback\",\n              \"type\": \"group\",\n              \"importance\": \"low\",\n              \"fields\": [\n                {\n                  \"name\": \"from\",\n                  \"type\": \"number\",\n                  \"label\": \"Score Range\",\n                  \"min\": 0,\n                  \"max\": 100,\n                  \"default\": 0,\n                  \"unit\": \"%\"\n                },\n                {\n                  \"name\": \"to\",\n                  \"type\": \"number\",\n                  \"min\": 0,\n                  \"max\": 100,\n                  \"default\": 100,\n                  \"unit\": \"%\"\n                },\n                {\n                  \"name\": \"feedback\",\n                  \"type\": \"text\",\n                  \"label\": \"Feedback for defined score range\",\n                  \"importance\": \"low\",\n                  \"placeholder\": \"Fill in the feedback\",\n                  \"optional\": true\n                }\n              ]\n            }\n          }\n        ]\n      },\n      {\n        \"name\": \"oldFeedback\",\n        \"type\": \"group\",\n        \"label\": \"Old Feedback\",\n        \"importance\": \"low\",\n        \"deprecated\": true,\n        \"fields\": [\n          {\n            \"name\": \"successGreeting\",\n            \"type\": \"text\",\n            \"label\": \"Quiz passed greeting\",\n            \"importance\": \"low\",\n            \"optional\": true,\n            \"description\": \"This text will be displayed above the score if the user has successfully passed the quiz.\",\n            \"tags\": [\n              \"strong\",\n              \"em\",\n              \"code\"\n            ]\n          },\n          {\n            \"name\": \"successComment\",\n            \"type\": \"text\",\n            \"widget\": \"html\",\n            \"label\": \"Passed comment\",\n            \"importance\": \"low\",\n            \"optional\": true,\n            \"description\": \"This comment will be displayed after the score if the user has successfully passed the quiz.\",\n            \"tags\": [\n              \"sub\",\n              \"sup\",\n              \"strong\",\n              \"em\",\n              \"a\",\n              \"p\",\n              \"code\"\n            ]\n          },\n          {\n            \"name\": \"failGreeting\",\n            \"type\": \"text\",\n            \"label\": \"Quiz failed title\",\n            \"importance\": \"low\",\n            \"optional\": true,\n            \"description\": \"This text will be displayed above the score if the user has failed the quiz.\",\n            \"tags\": [\n              \"strong\",\n              \"em\",\n              \"code\"\n            ]\n          },\n          {\n            \"name\": \"failComment\",\n            \"type\": \"text\",\n            \"widget\": \"html\",\n            \"label\": \"Failed comment\",\n            \"importance\": \"low\",\n            \"optional\": true,\n            \"description\": \"This comment will be displayed after the score if the user has failed the