INSERT INTO `mdl_notifications` VALUES (1,-10,2,'Default MoodleNet setting changed.',NULL,1,'<p>In Moodle 4.0 onwards, the <a href=\"https://moodle.net/\">MoodleNet</a> integration is enabled by default in Advanced features. Users with the capability to create and manage activities can browse MoodleNet via the activity chooser and import MoodleNet resources into their courses.</p><p>If desired, an alternative MoodleNet instance may be specified in the <a href=\"http://127.0.0.1:8080/admin/settings.php?section=tool_moodlenet\">MoodleNet settings</a>.</p>','In Moodle 4.0 onwards, the MoodleNet integration is enabled by default in Advanced features. Users with the capability to create and manage activities can browse MoodleNet via the activity chooser and import MoodleNet resources into their courses.If desired, an alternative MoodleNet instance may be specified in the MoodleNet settings.','moodle','notices','http://127.0.0.1:8080/admin/settings.php?section=optionalsubsystems#admin-enablemoodlenet','Advanced features',NULL,1684518065,NULL);
/*!40000 ALTER TABLE `mdl_notifications` ENABLE KEYS */;
UNLOCK TABLES;

