INSERT INTO `mdl_page` VALUES (1,2,'Prfungsstoff 1. Prfung','<p>Prfungsstoff 1. Prfung</p>',1,'<p style=\"color: #000000; font-family: arial,verdana,helvetica,sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: normal; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; background-color: #fafafa;\"><strong>Prfungsstoff:</strong></p>\n<ul style=\"color: #000000; font-family: arial,verdana,helvetica,sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: normal; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; background-color: #fafafa;\">\n<li style=\"font-family: arial,verdana,helvetica,sans-serif; font-size: 16px;\">Theorie und Beispiele Betriebssysteme, Nutzungsrechte an Software</li>\n<li style=\"font-family: arial,verdana,helvetica,sans-serif; font-size: 16px;\">Lehrmittel Kapitel Teil A (S. 13 - 36)</li>\n</ul>\n<p style=\"color: #000000; font-family: arial,verdana,helvetica,sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: normal; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; background-color: #fafafa;\"><strong>Lernziele:</strong></p>\n<ul style=\"color: #000000; font-family: arial,verdana,helvetica,sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: normal; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; background-color: #fafafa;\">\n<li style=\"font-family: arial,verdana,helvetica,sans-serif; font-size: 16px;\">Sie kennen die Grundbegriffe, die Aufgaben, den Aufbau und die Wechselwirkung des Betriebssystems.</li>\n<li style=\"font-family: arial,verdana,helvetica,sans-serif; font-size: 16px;\">Sie kennen Beispiele moderner Betriebssysteme und knnen Vor- und Nachteile abwgen.</li>\n<li style=\"font-family: arial,verdana,helvetica,sans-serif; font-size: 16px;\">Sie kennen Open-Source und Closed-Source Software, deren Vor- und Nachteile und knnen den Einsatzzweck bestimmen.</li>\n</ul>\n<p style=\"color: #000000; font-family: arial,verdana,helvetica,sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: normal; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; background-color: #fafafa;\"><strong>Hilfsmittel:</strong></p>\n<ul style=\"color: #000000; font-family: arial,verdana,helvetica,sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: normal; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; background-color: #fafafa;\">\n<li style=\"font-family: arial,verdana,helvetica,sans-serif; font-size: 16px;\">ausgedruckte Konsolebefehlsliste aus Klassenwiki</li>\n</ul>',1,2,NULL,5,'a:1:{s:10:\"printintro\";s:1:\"0\";}',2,1393419659),(2,2,'1. Prfung','',1,'1. Prfung',2,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1329928960),(3,2,'Frhlingsferien','',1,'Frhlingsferien ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1331909828),(4,2,'Frhlingsferien','',1,'Frhlingsferien ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1331909842),(5,2,'Prfungsstoff 2. Prfung (ISN2A)','',1,'\n<p style=\"color: rgb(0, 0, 0); font-family: arial,verdana,helvetica,sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: normal; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; background-color: rgb(250, 250, 250);\"><strong>Prfungsstoff:</strong></p>\n<ul>\n  <li>Lehrmittel Teil B (Kapitel 4 - 7)</li>\n  <li>Kapitel 12<br /></li>\n</ul>\n<p style=\"color: rgb(0, 0, 0); font-family: arial,verdana,helvetica,sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: normal; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; background-color: rgb(250, 250, 250);\"><strong>Lernziele:</strong></p>\n<ul style=\"color: rgb(0, 0, 0); font-family: arial,verdana,helvetica,sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: normal; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; background-color: rgb(250, 250, 250);\">\n  <li style=\"font-family: arial,verdana,helvetica,sans-serif; font-size: 16px;\">Sie kennen den Aufbau einer Festplatte und knnen die Partitionierung vornehmen und erklren. Weiter kennen Sie verschiedene Dateisysteme und deren Vor- und Nachteile.</li>\n  <li style=\"font-family: arial,verdana,helvetica,sans-serif; font-size: 16px;\">Sie knnen den Installationsumfang festlegen und kennen die wichtigsten Tools dazu. Weiter kennen Sie verschiedene Programme fr die einzelnen Betriebssysteme.<br /></li>\n  <li style=\"font-family: arial,verdana,helvetica,sans-serif; font-size: 16px;\">Sie knnen als Administrator arbeiten und grundlegende Konfigurationen vornehmen. Sie beherrschen dabei die Konsole und knnen die wichtigsten Befehle anwenden.<br /></li>\n</ul>\n<p style=\"color: rgb(0, 0, 0); font-family: arial,verdana,helvetica,sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: normal; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; background-color: rgb(250, 250, 250);\"><strong>Hilfsmittel:</strong></p> ausgedruckte Konsolebefehlsliste aus Klassenwiki ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1336368879),(6,2,'Prfungsstoff 2. Prfung (IAN2A, IAN2B, ISI2)','',1,'<p style=\"color: rgb(0, 0, 0); font-family: arial,verdana,helvetica,sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: normal; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; background-color: rgb(250, 250, 250);\"><strong>Prfungsstoff:</strong></p> \n<ul> \n  <li>Lehrmittel Teil B (Kapitel 4 - 7)</li> \n  <li>Kapitel 12<br /></li> \n</ul> \n<p style=\"color: rgb(0, 0, 0); font-family: arial,verdana,helvetica,sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: normal; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; background-color: rgb(250, 250, 250);\"><strong>Lernziele:</strong></p> \n<ul style=\"color: rgb(0, 0, 0); font-family: arial,verdana,helvetica,sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: normal; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; background-color: rgb(250, 250, 250);\"> \n  <li style=\"font-family: arial,verdana,helvetica,sans-serif; font-size: 16px;\">Sie kennen den Aufbau einer Festplatte und knnen die Partitionierung vornehmen und erklren. Weiter kennen Sie verschiedene Dateisysteme und deren Vor- und Nachteile.</li> \n  <li style=\"font-family: arial,verdana,helvetica,sans-serif; font-size: 16px;\">Sie knnen den Installationsumfang festlegen und kennen die wichtigsten Tools dazu. Weiter kennen Sie verschiedene Programme fr die einzelnen Betriebssysteme.<br /> </li> \n  <li style=\"font-family: arial,verdana,helvetica,sans-serif; font-size: 16px;\">Sie knnen als Administrator arbeiten und grundlegende Konfigurationen vornehmen. Sie beherrschen dabei die Konsole und knnen die wichtigsten Befehle anwenden.<br /></li> \n</ul> \n<p style=\"color: rgb(0, 0, 0); font-family: arial,verdana,helvetica,sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: normal; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; background-color: rgb(250, 250, 250);\"><strong>Hilfsmittel:</strong></p> ausgedruckte Konsolebefehlsliste aus Klassenwiki ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1336368891),(7,2,'Repetiton Modul 101','',1,'Repetiton Modul 101 fr Modulprfung ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1338362059),(8,2,'Modulprfungs- und Exkursionswoche','',1,'Modulprfungs- und Exkursionswoche ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1337933348),(9,3,'Prfungsstoff 1. Prfung','',1,'<div class=\"box generalbox generalboxcontent boxaligncenter clearfix\"> \n  <p><strong>Prfungsstoff:</strong></p> \n  <ul> \n    <li>Grundlagen (Windows-Explorer, Lokale Benutzerverwaltung, Dateien und Ressourcen freigeben</li> \n    <li>Grundlagen Word (Formatierungen), Umbrche, Spalten, Kopf- und Fusszeilen<br /></li> \n    <li>Lehrmittel Kapitel 1 - 5 (S. 6 - 47) </li> \n  </ul> \n  <p><strong>Lernziele:</strong></p> \n  <ul> \n    <li>Sie kennen den Windows-Explorer und knnen diesen anwenden.<br /></li> \n    <li>Sie kennen die Konzepte der Benutzerverwaltung, die Theorie der Freigaben und wissen was ein Dateisystem ist. </li> \n    <li>Sie knnen Zeichen, Abstze und Seiten unterschiedlich formatieren.<br /></li> \n    <li>Sie knnen mit Spalten, Kopf- und Fusszeilen in Word arbeiten</li> \n    <li>Sie kennen die Mglichkeiten der verschiedenen Umbrche und knnen diese anwenden.<br /></li> \n  </ul> \n  <p><strong>Hilfsmittel:</strong></p> \n  <ul> \n    <li>keine</li> \n  </ul></div> ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1345621362),(10,3,'Vorschau Lsung Umzugsplan','',1,'<img src=\"data:image/png;base64,\" /> ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1347428162),(11,3,'Prfungsstoff 2. Prfung','',1,'\n<div class=\"box generalbox generalboxcontent boxaligncenter clearfix\">\n  <div class=\"box generalbox generalboxcontent boxaligncenter clearfix\">\n    <p><strong>Prfungsstoff:</strong></p>\n    <ul>\n      <li>Grundlagen Word (Formatierungen), Umbrche, Spalten, Kopf- und Fusszeilen</li>\n      <li>Formatvorlagen</li>\n      <li>Weiterfhrende Textgestaltung, Tabellen</li>\n      <li>Illustrationen<br /></li>\n      <li>Lehrmittel Kapitel 4 - 8, 10 (S. 28 - 75 und S. 86 - 91) </li>\n    </ul>\n    <p><strong>Lernziele:</strong></p>\n    <ul>\n      <li>Sie knnen Zeichen, Abstze und Seiten unterschiedlich formatieren.<br /></li>\n      <li>Sie knnen mit Spalten, Kopf- und Fusszeilen in Word arbeiten</li>\n      <li>Sie kennen die Mglichkeiten der verschiedenen Umbrche und knnen diese anwenden.</li>\n      <li>Sie knnen Formatvorlagen erstellen, ndern und entsprechend einsetzen</li>\n      <li>Sie knnen Texte mit Tabstopps, Aufzhlungen und Rahmen gestalten</li>\n      <li>Sie knnen mit Tabellen in Word umgehen und entsprechend einer Vorgabe gestalten</li>\n      <li>Sie knnen Grafiken und Illustrationen in Word einfgen und anpassen<br /></li>\n    </ul>\n    <p><strong>Hilfsmittel:</strong></p>\n    <ul>\n      <li>Lehrmittel</li>\n    </ul></div> </div> ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1347428936),(12,3,'Herbstferien','',1,'Herbstferien ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1348035122),(13,3,'Herbstferien','',1,'Herbstferien ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1348035113),(14,3,'Herbstferien','',1,'Herbstferien ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1348035131),(15,3,'Auftrag Formatvorlage','',1,'Erstellen Sie in Excel eine neue Formatvorlage &quot;Resultat&quot;, die wie im nachfolgenden Bild formatiert ist:<br /><img width=\"91\" vspace=\"0\" hspace=\"0\" height=\"32\" border=\"0\" src=\"@@PLUGINFILE@@/formatvorlage.JPG\" alt=\"Formatvorlage Resultat\" title=\"Formatvorlage Resultat\" /><br /> ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1351059273),(16,3,'Auftrag Individuelle Liste fr die Ausfllfunktion','',1,'Erstellen Sie eine individuelle Liste fr die Ausfllfunktion mit folgenden Werten:<br />Firefox<br />Internet Explorer<br />Opera<br />Safari<br />Chrome<br /><br />Testen Sie Ihre eigene Liste mit der Ausfllfunktion.<br /> ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1351059662),(17,3,'Auftrag Illustrationen','',1,' Erstellen Sie mit Hilfe des Bildes novemer.jpg in Excel eine Illustration, die wie nachfolgend aussieht. Beachten Sie die ausgeblendeten Gitternetzlinien.<br /><img src=\"data:image/png;base64,\" /><br /> ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1351667450),(18,3,'Prfungsstoff 3. Prfung','',1,'<div class=\"box generalbox generalboxcontent boxaligncenter clearfix\"> \n  <div class=\"box generalbox generalboxcontent boxaligncenter clearfix\"> \n    <div class=\"box generalbox generalboxcontent boxaligncenter clearfix\"> \n      <p><strong>Prfungsstoff:</strong></p> \n      <ul> \n        <li>Lehrmittel Kapitel 13 - 21 (S. 108 - 187) </li> \n      </ul> \n      <p><strong>Lernziele:</strong></p> \n      <ul> \n        <li>Sie knnen Formatierungen in Excel anwenden.</li> \n        <li>Sie kennen die Druckmglichkeiten von Excel und knnen Kopf- und Fusszeilen einrichten.</li> \n        <li>Sie knnen Formatvorlagen und Mustervorlagen erstellen und kennen die Vorteile davon.</li> \n        <li>Sie kennen die Automatisierungshilfen von Excel und knnen diese erweitern.</li> \n        <li>Sie kennen die wichtigsten Zahlenformate und knnen Zellen entsprechend formatieren.</li> \n        <li>Sie knnen Illustrationen in Excel einfgen und formatieren.</li> \n        <li>Sie knnen relative, absolute und gemischte Bezge verwenden.</li> \n        <li>Sie knnen Spalten und Zeilen einfgen, lschen, ein- und ausblenden.</li> \n        <li>Sie knnen mit einfachen Funktionen Berechnungen in Excel ausfhren.</li> \n        <li>Sie knnen in Excel mit Datum und Uhrzeit Berechnungen ausfhren.<br /></li> \n      </ul> \n      <p><strong>Hilfsmittel:</strong></p> \n      <ul> \n        <li>Lehrmittel</li> \n      </ul></div> </div> </div> ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1352281485),(19,3,'3. Prfung','',1,'3. Prfung ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1353308638),(20,3,'Individuelles Arbeiten an Browser-Prsentationen','',1,'Individuelles Arbeiten an Browser-Prsentationen ',1,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1354084582),(21,3,'Prsentationen Browser','',1,'Prsentationen Browser',2,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1354531165),(22,3,'Weihnachtsferien','',1,'Weihnachtsferien',2,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1354523619),(23,3,'Weihnachtsferien','',1,'Weihnachtsferien',2,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1354523632),(24,3,'Firewall und Kryptografie','',1,'Fotos der Plakate sind im T-Laufwerk. ',2,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1355297048),(25,3,'Modulprfungswoche','',1,'Modulprfungswoche',2,2,NULL,5,'a:1:{s:10:\"printintro\";i:0;}',1,1354523684);
