LOCK TABLES `mdl_scale` WRITE;
/*!40000 ALTER TABLE `mdl_scale` DISABLE KEYS */;
INSERT INTO `mdl_scale` VALUES (1,0,0,'Anwendung von Einzelfakten oder ganzheitliche Wissensnutzung','Nutzt Wissen ber einzelne Fakten,Reflektiert das Wissen in Einzelfllen,Bercksichtigt den Gesamtzusammenhang und wgt Fakten ab','Die Skala basiert auf der Theorie von sachbezogenem, isoliertem und vernetztem, beziehungsorientiertem Denken (Belenky). Die Theorie beschreibt zwei unterschiedliche Wege, wie wir lernen und evaluieren knnen. <ul> <li><<strong>Getrennt/isoliert Denkende</strong> versuchen so objektiv wie mglich zu bleiben und Gefhle und Emotionen nicht zu bercksichtigen. In einer Diskussion mit anderen verteidigen Sie ihre Ideen und analysieren logisch die Ideen der anderen, um darin Schwachstellen zu finden.   </li><li> <strong>Vernetzt/beziehungsorientiert Denkende</strong> sind sehr empfindsam gegenber anderen Menschen. Sie sind gut trainiert, Empathie zu zeigen, anderen zuzuhren und Fragen zu stellen. Sie stellen eine Verbindung zu anderen her und knnen sich in deren Standpunkt hineinversetzen. Sie lernen durch den Austausch von Erfahrungen und das fhrt sie zu dem Wissen anderer Menschen. </li></ul>',0,1675269050),(2,0,0,'Standard-Kompetenzskala','Kompetenz noch nicht vorhanden,Kompetenz vorhanden','Eine binre Bewertungsskala, die ber keine weiteren Angaben verfgt, ob Kenntnisse und Fertigkeiten unter Beweis gestellt wurden.',0,1675269050),(3,0,2,'Noten 1-6','1, 1.25, 1.5, 1.75, 2, 2.25, 2.5, 2.75, 3, 3.25, 3.5, 3.75, 4, 4.25, 4.5, 4.75, 5, 5.25, 5.5, 5.75, 6','',1,1305120182);
/*!40000 ALTER TABLE `mdl_scale` ENABLE KEYS */;
UNLOCK TABLES;

